import * as LanguageServiceNS from './LanguageService'

interface HostRuntime {
  readonly version: string
  readonly modules: Record<string, unknown>
}

export const installHostRuntime = (
  tsdk: typeof import('typescript'),
): void => {
  ;(globalThis as Record<string, unknown>)[runtimeKey] = {
    version: runtimeVersion,
    modules: {
      effect: EffectNS,
      '@athrio/loom-lang-services/LanguageService': LanguageServiceNS,
      typescript: tsdk,
    },
  } satisfies HostRuntime
}

export const workspaceRoot = (dir: string): string => {
  const seek = (at: string): string | undefined => {
    if (existsSync(join(at, '.loom'))) return at
    const parent = dirname(at)
    return parent === at ? undefined : seek(parent)
  }
  return seek(dir) ?? dir
}

export const storeDir = (dir: string): string =>
  process.env.LOOM_HOME === undefined
    ? join(workspaceRoot(dir), '.loom', 'services')
    : join(process.env.LOOM_HOME, 'services')

const servicePrefix = 'loom-service-'

export const installedServices = (
  dir: string,
): Effect.Effect<ReadonlyArray<string>> =>
  Effect.sync(() => {
    const scope = join(storeDir(dir), 'node_modules', '@athrio')
    if (!existsSync(scope)) return []
    return readdirSync(scope)
      .filter((name) => name.startsWith(servicePrefix))
      .map((name) => name.slice(servicePrefix.length))
  })

export class StoreError extends Data.TaggedError('StoreError')<{
  readonly id: string
  readonly cause: unknown
}> {}

const prepareStore = (store: string): void => {
  mkdirSync(store, { recursive: true })
  const manifest = join(store, 'package.json')
  if (!existsSync(manifest))
    writeFileSync(
      manifest,
      `${JSON.stringify({ name: 'loom-services', private: true }, null, 2)}\n`,
    )
}

export const addService = (
  id: string,
  dir: string,
): Effect.Effect<void, StoreError> =>
  Effect.gen(function* () {
    const store = storeDir(dir)
    if (existsSync(join(store, 'node_modules', servicePackage(id)))) return
    yield* Effect.sync(() => prepareStore(store))
    yield* Effect.tryPromise({
      try: () =>
        run('npm', [
          'install',
          servicePackage(id),
          '--prefix',
          store,
          '--omit=peer',
          '--no-audit',
          '--no-fund',
        ]),
      catch: (cause) => new StoreError({ id, cause }),
    }).pipe(Effect.asVoid)
  })

export const removeService = (id: string, dir: string): Effect.Effect<void> =>
  Effect.sync(() =>
    rmSync(join(storeDir(dir), 'node_modules', servicePackage(id)), {
      recursive: true,
      force: true,
    }),
  )

const loadService = (
  id: string,
  root: string,
): Effect.Effect<Option.Option<LanguageService>> =>
  Effect.tryPromise(async () => {
    const from = join(storeDir(dirname(root)), 'index.js')
    const entry = createRequire(from).resolve(servicePackage(id))
    const loaded = (await import(pathToFileURL(entry).href)) as {
      readonly default?: unknown
    }
    return loaded.default
  }).pipe(
    Effect.flatMap((exported) =>
      isLanguageService(exported) && exported.id === id
        ? Effect.succeed(Option.some(exported))
        : Effect.logWarning(
            `${servicePackage(id)} does not export a language service for "${id}"`,
          ).pipe(Effect.as(Option.none<LanguageService>())),
    ),
    Effect.catchAll(() =>
      Effect.logWarning(
        `language "${id}" is activated but ${servicePackage(id)} is not installed — run \`loom add ${id}\``,
      ).pipe(Effect.as(Option.none<LanguageService>())),
    ),
  )

